import random
from collections import defaultdict

def create_maze(width, height):
    visited = set()
    stack = [(1, 1)]
    directions = [(-2, 0), (2, 0), (0, -2), (0, 2)]

    def in_bounds(x, y):
        return 0 < x < width and 0 < y < height

    while stack:
        x, y = stack[-1]
        visited.add((x, y))

        options = []
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if in_bounds(nx, ny) and (nx, ny) not in visited:
                cnt = sum(1 for ddx, ddy in directions if (nx + ddx, ny + ddy) in visited)
                if cnt == 1:
                    options.append((dx, dy))

        if not options:
            stack.pop()
        else:
            dx, dy = random.choice(options)
            stack.append((x + dx, y + dy))
            visited.add((x + dx, y + dy))
            visited.add((x + dx // 2, y + dy // 2))

    return visited


def display_ascii_maze(maze, width, height):
    for y in range(height):
        row = ''
        for x in range(width):
            if (x, y) in maze:
                row += ' '
            elif x % 2 == 0 and y % 2 == 0:
                row += '+'
            elif x % 2 == 0:
                row += '|'
            else:
                row += '-'
        print(row)


if __name__ == "__main__":
    width, height = 21, 11
    maze = create_maze(width, height)
    display_ascii_maze(maze, width, height)
